import os, json, re
from openai import OpenAI

client = OpenAI(api_key=os.environ["OPENAI_API_KEY"])

def extract_json_from_text(text: str) -> str:
    """Strip markdown fences and extract the JSON object."""
    text = text.strip()
    match = re.search(r"```(?:json)?\s*(\{.*?\})\s*```", text, re.DOTALL)
    if match:
        return match.group(1)
    match = re.search(r"\{.*\}", text, re.DOTALL)
    if match:
        return match.group(0)
    raise ValueError(f"No JSON found: {text[:200]!r}")

def call_with_retry(messages: list, model_class, schema_prompt: str, max_retries: int = 3):
    """Call the LLM and retry with error context on parse or validation failure."""
    full_msgs = [{"role": "system", "content": schema_prompt}] + messages
    for attempt in range(max_retries):
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            response_format={"type": "json_object"},
            messages=full_msgs,
            temperature=0,
        )
        raw = response.choices[0].message.content
        try:
            parsed = json.loads(extract_json_from_text(raw))
            return model_class.model_validate(parsed)
        except Exception as e:
            if attempt == max_retries - 1:
                raise RuntimeError(f"Failed after {max_retries} attempts: {e}") from e
            full_msgs = full_msgs + [
                {"role": "assistant", "content": raw},
                {"role": "user", "content": (
                    f"Your response was invalid: {e}. "
                    "Return only a corrected JSON object matching the schema."
                )},
            ]
    raise RuntimeError("Unreachable")  # pragma: no cover
